    12→/**
    13→ * Import Service for file parsing and data extraction
    14→ */
    15→class AHGMH_Import_Service {
    16→
    17→    private $upload_dir;
    18→    private $allowed_mime_types;
    19→    private $max_file_size;
    20→
    21→    /**
    22→     * Constructor
    23→     */
    24→    public function __construct() {
    25→        $this->upload_dir = wp_upload_dir();
    26→        $this->allowed_mime_types = [
    27→            'text/csv',
    28→            'text/plain',
    29→            'application/csv',
    30→            'application/vnd.ms-excel',
    31→            'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    32→        ];
    33→        $this->max_file_size = 5 * 1024 * 1024; // 5MB
    34→    }
    35→
    36→    /**
    37→     * Handle file upload
    38→     *
    39→     * @param array $file The uploaded file from $_FILES
    40→     * @return array Upload result with filepath and metadata
    41→     * @throws Exception On upload or validation failure
    42→     */
    43→    public function handle_upload($file) {
    44→        // Validate file upload
    45→        if (!isset($file['error']) || is_array($file['error'])) {
    46→            throw new Exception(__('Ungültige Datei-Parameter.', 'abschussplan-hgmh'));
    47→        }
    48→
    49→        // Check upload errors
    50→        switch ($file['error']) {
    51→            case UPLOAD_ERR_OK:
    52→                break;
    53→            case UPLOAD_ERR_INI_SIZE:
    54→            case UPLOAD_ERR_FORM_SIZE:
    55→                throw new Exception(__('Datei überschreitet die maximale Dateigröße.', 'abschussplan-hgmh'));
    56→            case UPLOAD_ERR_NO_FILE:
    57→                throw new Exception(__('Keine Datei hochgeladen.', 'abschussplan-hgmh'));
    58→            default:
    59→                throw new Exception(__('Upload-Fehler aufgetreten.', 'abschussplan-hgmh'));
    60→        }
    61→
    62→        // Validate file size
    63→        if ($file['size'] > $this->max_file_size) {
    64→            throw new Exception(sprintf(
    65→                __('Datei ist zu groß. Maximum: %s', 'abschussplan-hgmh'),
    66→                $this->format_file_size($this->max_file_size)
    67→            ));
    68→        }
    69→
    70→        // Validate file type
    71→        $finfo = finfo_open(FILEINFO_MIME_TYPE);
    72→        $mime_type = finfo_file($finfo, $file['tmp_name']);
    73→        finfo_close($finfo);
    74→
    75→        if (!in_array($mime_type, $this->allowed_mime_types)) {
    76→            throw new Exception(__('Dateityp nicht unterstützt. Bitte CSV oder Excel-Dateien verwenden.', 'abschussplan-hgmh'));
    77→        }
    78→
    79→        // Generate secure filename
    80→        $extension = pathinfo($file['name'], PATHINFO_EXTENSION);
    81→        $filename = AHGMH_Validation_Service::generate_secure_filename('import', $extension);
    82→        $filepath = $this->upload_dir['path'] . '/' . $filename;
    83→
    84→        // Move uploaded file
    85→        if (!move_uploaded_file($file['tmp_name'], $filepath)) {
    86→            throw new Exception(__('Datei konnte nicht gespeichert werden.', 'abschussplan-hgmh'));
    87→        }
    88→
    89→        // Schedule cleanup after 1 hour
    90→        wp_schedule_single_event(time() + 3600, 'ahgmh_cleanup_import_file', [$filepath]);
    91→
    92→        return [
    93→            'filepath' => $filepath,
    94→'filename' => sanitize_file_name($file['name']),
    95→            'size' => $file['size'],
    96→            'mime_type' => $mime_type,
    97→            'extension' => sanitize_text_field($extension)
    98→        ];
    99→    }
   100→
   101→    /**
   102→     * Parse uploaded file and extract data
   103→     *
   104→     * @param string $filepath Path to the uploaded file
   105→     * @return array Parsed data with headers and rows
   106→     * @throws Exception On parsing failure
   107→     */
   108→    public function parse_file($filepath) {
   109→        if (!file_exists($filepath)) {
   110→            throw new Exception(__('Datei nicht gefunden.', 'abschussplan-hgmh'));
   111→        }
   112→
   113→        $extension = strtolower(pathinfo($filepath, PATHINFO_EXTENSION));
   114→
   115→        switch ($extension) {
   116→            case 'csv':
   117→            case 'txt':
   118→                return $this->parse_csv($filepath);
   119→
   120→            case 'xlsx':
   121→            case 'xls':
   122→                return $this->parse_excel($filepath);
   123→
   124→            default:
   125→                throw new Exception(__('Nicht unterstütztes Dateiformat.', 'abschussplan-hgmh'));
   126→        }
   127→    }
   128→
   129→    /**
   130→     * Parse CSV file with automatic delimiter and encoding detection
   131→     *
   132→     * @param string $filepath Path to CSV file
   133→     * @return array Parsed data with headers and rows
   134→     * @throws Exception On parsing failure
   135→     */
   136→    private function parse_csv($filepath) {
   137→        // Read file and detect encoding
   138→        $content = file_get_contents($filepath);
   139→
   140→        if ($content === false) {
   141→            throw new Exception(__('Datei konnte nicht gelesen werden.', 'abschussplan-hgmh'));
   142→        }
   143→
   144→        // Remove UTF-8 BOM if present
   145→        $content = $this->remove_bom($content);
   146→
   147→        // Detect and convert encoding
   148→        $content = $this->convert_encoding($content);
   149→
   150→        // Detect delimiter (comma or semicolon for German Excel exports)
   151→        $delimiter = $this->detect_delimiter($content);
   152→
   153→        // Parse CSV content
   154→        $lines = str_getcsv($content, "\n");
   155→        $data = [];
   156→
   157→        foreach ($lines as $line) {
   158→            if (empty(trim($line))) {
   159→                continue; // Skip empty lines
   160→            }
   161→            $data[] = str_getcsv($line, $delimiter);
   162→        }
   163→
   164→        if (empty($data)) {
   165→            throw new Exception(__('Datei enthält keine Daten.', 'abschussplan-hgmh'));
   166→        }
   167→
   168→        // Extract headers (first row)
   169→        $headers = array_shift($data);
   170→
   171→        // Sanitize headers
   172→        $headers = array_map(function($header) {
   173→            return sanitize_text_field(trim($header));
   174→        }, $headers);
   175→
   176→        // Sanitize data rows
   177→        $sanitized_data = [];
   178→        foreach ($data as $row) {
   179→            if (count($row) === count($headers)) {
   180→                $sanitized_row = array_map(function($cell) {
   181→                    return sanitize_text_field(trim($cell));
   182→                }, $row);
   183→                $sanitized_data[] = $sanitized_row;
   184→            }
   185→        }
   186→
   187→        return [
   188→            'headers' => $headers,
   189→            'data' => $sanitized_data,
   190→            'row_count' => count($sanitized_data),
   191→            'column_count' => count($headers),
   192→            'delimiter' => $delimiter === ';' ? 'semicolon' : 'comma'
   193→        ];
   194→    }
   195→
   196→    /**
   197→     * Parse Excel file
   198→     *
   199→     * @param string $filepath Path to Excel file
   200→     * @return array Parsed data with headers and rows
   201→     * @throws Exception On parsing failure
   202→     */
   203→    private function parse_excel($filepath) {
   204→        // Check if PhpSpreadsheet is available
   205→        if (class_exists('\PhpOffice\PhpSpreadsheet\IOFactory')) {
   206→            return $this->parse_excel_with_library($filepath);
   207→        }
   208→
   209→        // Fallback: Try to read as CSV if Excel library not available
   210→        // Many .xls files exported from Excel are actually CSV with different extension
   211→        try {
   212→            return $this->parse_csv($filepath);
   213→        } catch (Exception $e) {
   214→            throw new Exception(__('Excel-Unterstützung nicht verfügbar. Bitte konvertieren Sie die Datei zu CSV oder installieren Sie PhpSpreadsheet.', 'abschussplan-hgmh'));
   215→        }
   216→    }
   217→
   218→    /**
   219→     * Parse Excel file using PhpSpreadsheet library
   220→     *
   221→     * @param string $filepath Path to Excel file
   222→     * @return array Parsed data with headers and rows
   223→     * @throws Exception On parsing failure
   224→     */
   225→    private function parse_excel_with_library($filepath) {
   226→        try {
   227→            $spreadsheet = \PhpOffice\PhpSpreadsheet\IOFactory::load($filepath);
   228→            $worksheet = $spreadsheet->getActiveSheet();
   229→            $rows = $worksheet->toArray();
   230→
   231→            if (empty($rows)) {
   232→                throw new Exception(__('Excel-Datei enthält keine Daten.', 'abschussplan-hgmh'));
   233→            }
   234→
   235→            // Extract headers
   236→            $headers = array_shift($rows);
   237→
   238→            // Sanitize headers
   239→            $headers = array_map(function($header) {
   240→                return sanitize_text_field(trim($header));
   241→            }, $headers);
   242→
   243→            // Sanitize data rows
   244→            $sanitized_data = [];
   245→            foreach ($rows as $row) {
   246→                if (count($row) === count($headers)) {
   247→                    $sanitized_row = array_map(function($cell) {
   248→                        return sanitize_text_field(trim($cell));
   249→                    }, $row);
   250→                    $sanitized_data[] = $sanitized_row;
   251→                }
   252→            }
   253→
